command:
mkdir -p space .claude-tdd-pro/space && printf 'metrics:
  - {id: space-perf-rubric-pass-rate, dimension: performance}
' > space/metrics.yaml && printf 'collected:
  - {id: space-unknown-metric, value: 0.5}
' > .claude-tdd-pro/space/collected.yaml && printf 'dimensions:
  performance: {enabled: true}
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/space-report.sh" --metrics space/metrics.yaml --collected .claude-tdd-pro/space/collected.yaml --config space/config.yaml 2>out.txt && grep -q 'warning' out.txt && grep -q 'space-unknown-metric' out.txt && echo ok 1>&2
